import { CUSTOM_HANDLE_PATH_CLASSNAME } from '../../../../legend/legend-constants';
import { getHandleData } from '../../../../legend/size-legend/slider/size-slider-helpers';

export function styleHandles(behaviourEventInstance, selectionManager) {
    let _instance = behaviourEventInstance.instance,
        customHandles = _instance.customHandles;

    if (!customHandles) {
        return;
    }

    let handles = customHandles.selectAll(`path.${CUSTOM_HANDLE_PATH_CLASSNAME}`),
        { brushOptions } = _instance.options.component,
        { handles: handleOptions, markerBound } = brushOptions,
        { width, height } = markerBound,
        //
        point = selectionManager.point,
        data = getHandleData(brushOptions, point);

    if (!handleOptions) {
        return;
    }

    let { shape, transform } = handleOptions;

    handles.attrs({
        d: d => shape(width(data[d.i]), height(data[d.i])),
        transform: d => transform(data[d.i])
    });
}
